332	    {
333	        if (! isset(static::$booted[static::class])) {
334	            if (isset(static::$booting[static::class])) {
335	                throw new LogicException('The ['.__METHOD__.'] method may not be called on model ['.static::class.'] while it is being booted.');
336	            }
337	
338	            static::$booting[static::class] = true;
339	
340	            $this->fireModelEvent('booting', false);
341	
342	            static::booting();
343	            static::boot();
344	
345	            static::$booted[static::class] = true;
346	            unset(static::$booting[static::class]);
347	
348	            static::booted();
349	
350	            static::$bootedCallbacks[static::class] ??= [];
351	
352	            foreach (static::$bootedCallbacks[static::class] as $callback) {
353	                $callback();
