381	     * Boot all of the bootable traits on the model.
382	     *
383	     * @return void
384	     */
385	    protected static function bootTraits()
386	    {
387	        $class = static::class;
388	
389	        $booted = [];
390	
391	        static::$traitInitializers[$class] = [];
392	
393	        $uses = class_uses_recursive($class);
394	
395	        $conventionalBootMethods = array_map(static fn ($trait) => 'boot'.class_basename($trait), $uses);
396	        $conventionalInitMethods = array_map(static fn ($trait) => 'initialize'.class_basename($trait), $uses);
397	
398	        foreach ((new ReflectionClass($class))->getMethods() as $method) {
399	            if (! in_array($method->getName(), $booted) &&
400	                $method->isStatic() &&
401	                (in_array($method->getName(), $conventionalBootMethods) ||
402	                $method->getAttributes(Boot::class) !== [])) {
403	                $method->invoke(null);
404	
405	                $booted[] = $method->getName();
406	            }
407	
408	            if (in_array($method->getName(), $conventionalInitMethods) ||
409	                $method->getAttributes(Initialize::class) !== []) {
410	                static::$traitInitializers[$class][] = $method->getName();
411	            }
412	        }
413	
414	        static::$traitInitializers[$class] = array_unique(static::$traitInitializers[$class]);
415	    }
