437	
438	        $reflection = new ReflectionClass(static::class);
439	
440	        $declaresTable = $reflection->hasProperty('table')
441	            && $reflection->getProperty('table')->getDeclaringClass()->getName() === static::class;
442	
443	        if (! $declaresTable && $reflection->getAttributes(Table::class) !== []) {
444	            $this->table = $table->name ?? null;
445	        } else {
446	            $this->table ??= $table->name ?? null;
447	        }
448	
449	        $this->connection ??= static::resolveClassAttribute(Connection::class, 'name');
450	
451	        if ($this->primaryKey === 'id' && $table && $table->key !== null) {
452	            $this->primaryKey = $table->key;
453	        }
454	
455	        if ($this->keyType === 'int' && $table && $table->keyType !== null) {
456	            $this->keyType = $table->keyType;
457	        }
458	
459	        if (static::resolveClassAttribute(WithoutIncrementing::class) !== null) {
460	            $this->incrementing = false;
461	        } elseif ($table && $table->incrementing !== null) {
