538	    {
539	        $class = $class ?: static::class;
540	
541	        if (! $class::UPDATED_AT) {
542	            return true;
543	        }
544	
545	        $timestamps = static::resolveClassAttribute(Table::class, 'timestamps', $class)
546	            ?? get_class_vars($class)['timestamps'];
547	
548	        if (! $timestamps) {
549	            return true;
550	        }
551	
552	        foreach (static::$ignoreOnTouch as $ignoredClass) {
553	            if ($class === $ignoredClass || is_subclass_of($class, $ignoredClass)) {
554	                return true;
555	            }
556	        }
557	
558	        return false;
559	    }
