672	    /**
673	     * Fill the model with an array of attributes.
674	     *
675	     * @param  array<string, mixed>  $attributes
676	     * @return $this
677	     *
678	     * @throws \Illuminate\Database\Eloquent\MassAssignmentException
679	     */
680	    public function fill(array $attributes)
681	    {
682	        $totallyGuarded = $this->totallyGuarded();
683	
684	        $fillable = $this->fillableFromArray($attributes);
685	
686	        foreach ($fillable as $key => $value) {
687	            // The developers may choose to place some attributes in the "fillable" array
688	            // which means only those attributes may be set through mass assignment to
689	            // the model, and all others will just get ignored for security reasons.
690	            if ($this->isFillable($key)) {
691	                $this->setAttribute($key, $value);
692	            } elseif ($totallyGuarded || static::preventsSilentlyDiscardingAttributes()) {
693	                if (isset(static::$discardedAttributeViolationCallback)) {
694	                    call_user_func(static::$discardedAttributeViolationCallback, $this, [$key]);
695	                } else {
696	                    throw new MassAssignmentException(sprintf(
697	                        'Add [%s] to fillable property to allow mass assignment on [%s].',
698	                        $key, get_class($this)
699	                    ));
700	                }
701	            }
702	        }
703	
704	        if (count($attributes) !== count($fillable) &&
705	            static::preventsSilentlyDiscardingAttributes()) {
706	            $keys = array_diff(array_keys($attributes), array_keys($fillable));
707	
708	            if (isset(static::$discardedAttributeViolationCallback)) {
709	                call_user_func(static::$discardedAttributeViolationCallback, $this, $keys);
710	            } else {
711	                throw new MassAssignmentException(sprintf(
712	                    'Add fillable property [%s] to allow mass assignment on [%s].',
713	                    implode(', ', $keys),
714	                    get_class($this)
715	                ));
716	            }
717	        }
718	
719	        return $this;
720	    }
